import os, json, torch

def main():
    os.makedirs("checkpoints/baseline", exist_ok=True)
    torch.save({"version": "tunable_v2"}, "checkpoints/baseline/policy.pt")
    cfg = {"dist_denom": 2.0, "reverse_penalty": 0.3, "visited_penalty": 0.1, "persist_boost": 1.05}
    with open("checkpoints/baseline/planner_cfg.json", "w") as f:
        json.dump(cfg, f)
    print("Saved checkpoint and tuned planner config")

if __name__ == "__main__":
    main()
